# Module for shape hierarchy with interfaces

interface IShape:
    def area(self) -> float: ...

    def perimeter(self) -> float: ...

    property get name(self) -> str: ...

class ShapeBase:
    _id: int

    @static
    next_id: int = 1

    def __init__(self):
        self._id = ShapeBase.next_id
        ShapeBase.next_id += 1

    @virtual
    def area(self) -> float:
        return 0.0

    @virtual
    def perimeter(self) -> float:
        return 0.0

    @virtual
    def describe(self) -> str:
        return f"Shape #{self._id}"

    property get id(self) -> int:
        return self._id

class Rectangle(ShapeBase):
    width: float
    height: float

    def __init__(self, width: float, height: float):
        super().__init__()
        self.width = width
        self.height = height

    @override
    def area(self) -> float:
        return self.width * self.height

    @override
    def perimeter(self) -> float:
        return 2.0 * (self.width + self.height)

    @override
    def describe(self) -> str:
        return f"Rectangle {self.width}x{self.height}"

class Circle(ShapeBase):
    radius: float

    def __init__(self, radius: float):
        super().__init__()
        self.radius = radius

    @override
    def area(self) -> float:
        import math
        return math.pi * self.radius * self.radius

    @override
    def perimeter(self) -> float:
        import math
        return 2.0 * math.pi * self.radius

    @override
    def describe(self) -> str:
        return f"Circle r={self.radius}"

