# Module for geometry primitives, enums, and structs

enum Color:
    RED = 1
    GREEN = 2
    BLUE = 3
    YELLOW = 4

struct Point:
    x: float
    y: float

    def __init__(self, x: float, y: float):
        self.x = x
        self.y = y

    def distance_to(self, other: Point) -> float:
        dx: float = self.x - other.x
        dy: float = self.y - other.y
        return (dx * dx + dy * dy) ** 0.5

    def __str__(self) -> str:
        return f"({self.x}, {self.y})"

class ColoredPoint(Point):
    color: Color

    def __init__(self, x: float, y: float, color: Color):
        super().__init__(x, y)
        self.color = color

    def __str__(self) -> str:
        color_name: str = self.color.name
        return f"({self.x}, {self.y})[{color_name}]"

def get_quadrant(p: Point) -> str:
    if p.x >= 0.0 and p.y >= 0.0:
        return "Q1"
    elif p.x < 0.0 and p.y >= 0.0:
        return "Q2"
    elif p.x < 0.0 and p.y < 0.0:
        return "Q3"
    else:
        return "Q4"

