# Utility functions for shape processing

from shapes import ShapeBase, Rectangle, Circle
from geometry import Point, Color, ColoredPoint

def process_shapes(shapes: list[ShapeBase]) -> tuple[float, float]:
    total_area: float = 0.0
    total_perimeter: float = 0.0

    for shape in shapes:
        total_area += shape.area()
        total_perimeter += shape.perimeter()

    return (total_area, total_perimeter)

def create_test_points() -> list[Point]:
    points: list[Point] = []
    points.append(Point(0.0, 0.0))
    points.append(Point(3.0, 4.0))
    points.append(ColoredPoint(-2.0, 5.0, Color.BLUE))
    points.append(ColoredPoint(-1.0, -1.0, Color.GREEN))
    return points

@final
class ShapeStats:
    count: int
    @static
    instance: ShapeStats?

    def __init__(self):
        self.count = 0

    @static
    def get_instance() -> ShapeStats:
        if ShapeStats.instance is None:
            ShapeStats.instance = Some(ShapeStats())
        return ShapeStats.instance.unwrap()

    def increment(self) -> None:
        self.count += 1
